SELECT *
FROM User
WHERE department_id = #{departmentId}
  AND NOT role_id = 2;

SELECT *
FROM User
WHERE id = #{userId}
  AND NOT role_id = 2;

SELECT *
FROM SigninUser
WHERE activity_name = #{activityName}
  and status = 1;

SELECT *
FROM SigninUser
WHERE activity_name = #{activityName}
  and status = 0;

SELECT id, username, role_id
FROM User
WHERE department_id = #{departmentId};

SELECT COUNT(*)
FROM SigninUser
WHERE activity_name = #{activityName}

select status
from SigninUser
where user_name = #{userName}
  and id = #{id}
  and activity_name = #{activityName}

select department_id
from SigninUser
where user_name = #{userName}
  and id = #{id}
  and activity_name = #{activityName}
